27	const PROCESSING_FEE = 5;
28	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
29	const BLOCK_OF_THREE_DISCOUNT = 15;
30	
31	const BASE_PREMIUM: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	const blockOfThreeDiscount = (alikeComponentCount: number): number =>
41	  alikeComponentCount === 3 ? BLOCK_OF_THREE_DISCOUNT : 0;
42	
43	const COMPONENT_TYPES = ["rune", "moonstone"];
44	
45	const countItemsOfType = (items: Item[], type: string): number =>
46	  items.filter((item) => item.type === type).length;
47	
48	const CURSE_SURCHARGE_RATE = 0.5;
49	
50	const sumItemSpecificSurcharges = (items: Item[]): number =>
51	  items.reduce((sum, item) => {
52	    const base = BASE_PREMIUM[item.type];
53	    const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
54	    return sum + curse;
55	  }, 0);
56	
57	const calculateBasePremium = (items: Item[]): number => {
58	  const subtotal = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
59	  const totalDiscount = COMPONENT_TYPES.reduce(
60	    (sum, type) => sum + blockOfThreeDiscount(countItemsOfType(items, type)),
61	    0,
62	  );
63	  return subtotal - totalDiscount;
64	};
65	
66	const quote = (step: QuoteStep): QuoteResult => {
67	  const basePremium = calculateBasePremium(step.items);
68	  const itemSurcharges = sumItemSpecificSurcharges(step.items);
69	  const firstInsurance = basePremium * FIRST_CONTRACT_SURCHARGE_RATE;
70	  const premium = Math.ceil(basePremium + itemSurcharges + firstInsurance + PROCESSING_FEE);
71	  return { premium };
72	};
73	
74	export const runScenario = (scenario: Scenario): ScenarioResult => {
75	  const results = scenario.steps.map(quote);
76	  return { results };
77	};
